// Animation loop
const canvas = new TVG.Canvas('#canvas');
const shape = new TVG.Shape();

let rotation = 0;
function animate() {
  shape.reset()
       .appendRect(0, 0, 100, 100)
       .fill(100, 150, 255, 255)
       .rotate(rotation++)
       .translate(400, 300);

  canvas.update().render();
  requestAnimationFrame(animate);
}
animate();
