const sin = Math.sin(rad);

shape.transform({
  e11: 2 * cos,   e12: -2 * sin,  e13: 100,
  e21: 1.5 * sin, e22: 1.5 * cos, e23: 50,
  e31: 0,         e32: 0,         e33: 1
});
